var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 11월 8일 런던, 화이트 채플","JPN":"1888年11月8日　ロンドン、ホワイトチャペル","ENG":"November 8, 1888, London, White Chapel","TWN":"1888年11月8日 倫敦，白教堂","SCN":"1888年11月8日 伦敦，白教堂","DEU":"November 8, 1888, London, White Chapel","FRA":"November 8, 1888, London, White Chapel"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"이제 이것만 다 하면…….","JPN":"もうこれさえ終われば……","ENG":"I'll be done after I finish this...","TWN":"現在只要把這個做完……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"어때, 좀 할만해?","JPN":"どう？　ちゃんとできそう？","ENG":"Adjusting well?","TWN":"怎麼樣，還能應付嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"원래 세탁부가 일이 좀 고된 편이거든.","JPN":"もともと洗濯担当は仕事が多くて大変なの。","ENG":"Being in charge of the laundry is hard work.","TWN":"原本洗衣工的工作就有點辛苦。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"괜찮아요. 거의 다 끝났거든요. 안젤리나 씨.","JPN":"大丈夫です。ほぼ終わりました。アンジェリーナさん。","ENG":"It's fine. I'm almost done, anyway, Miss Angelina.","TWN":"沒關係。差不多都結束了，安潔莉娜。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"정말? 오늘은 세탁물이 좀 많았는데 대단하네.","JPN":"本当に？　今日は洗濯物が多かったのに、すごいわ。","ENG":"Really? Wow. It looked like there was a lot of laundry today.","TWN":"真的嗎？今天的洗衣量有點多，真厲害～"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"극장에서 일하다 왔다고 했지?","JPN":"以前は劇場で働いてたって言ったわよね？","ENG":"Didn't you say that you used to work at a theater?","TWN":"你說你以前在劇院工作，對吧？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"갑자기 몸 쓰는 일을 하게 돼서, 힘들어 할 줄 알았는데, 금방 적응하는구나?","JPN":"いきなり力仕事なんて大変だと思ったのに、すぐ慣れちゃって。","ENG":"I thought you'd have a hard time with the sudden hard labor, but it seems like you're adjusting well.","TWN":"突然要做體力活，本以為會很辛苦，沒想到你適應得挺快的~"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"하하, 원래 극장에서도 스태프는 몸 쓰는 일을 많이 해서 익숙하거든요.","JPN":"ハハッ、劇場でもスタッフは力仕事が多いですから、慣れてるんです。","ENG":"Haha, the staff at a theater also do a lot of heavy lifting, so I'm used to it.","TWN":"呵呵，本來在劇院裡做助理就經常幹體力活，所以已經習慣了。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"이제, 그 극장은 사라지고 없지만…….","JPN":"もう、あの劇場はありませんけど……","ENG":"But that theater is gone now...","TWN":"只是那家劇院已經不復存在了……"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"어머, 내가 괜한 소리를 했나 보네.","JPN":"あら、余計なことを聞いちゃったみたいね。","ENG":"Oh, my. I'm sorry for bringing it up.","TWN":"啊，我是不是說了不該說的話……"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 나도 거들 테니까 얼른 마치고 같이 퇴근하지 않을래?","JPN":"じゃあ、私も手伝うから早く終わらせて一緒に帰りましょう？","ENG":"Then, I'll help out. Let's get this done and clock off together, okay?","TWN":"我也來幫忙吧，快點完成一起下班怎麼樣？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"요즘 런던 거리 분위기가 좀 뒤숭숭 하잖아. 심야의 살인마 건도 그렇고.","JPN":"最近ロンドンの街って、あまり雰囲気がよくはないじゃない。深夜の殺人鬼もいるし。","ENG":"The London streets are a bit chaotic these days including the Midnight Killer case.","TWN":"最近倫敦街頭的氣氛有點不安。午夜殺人魔的事件也是。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"네, 저야 좋죠.","JPN":"はい、ありがとうございます。","ENG":"Okay. I'd like that.","TWN":"好，我沒問題。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 11월 9일 런던, 화이트 채플\\n<color=#ffd34c>심야</color>","JPN":"1888年11月9日　ロンドン、ホワイトチャペル\\n<color=#ffd34c>深夜</color>","ENG":"[[","TWN":"1888年11月9日 倫敦，白教堂<color=#ffd34c>深夜</color>","SCN":"1888年11月9日 伦敦，白教堂<color=#ffd34c>深夜</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"왕실은 언제까지 시민들을 불안에 떨게 만들 생각인가!","JPN":"王室はいつまで市民に不安な思いをさせるつもりなんだ！","ENG":"How much longer is the royal family going to ignore the cries of the people?!","TWN":"王室打算讓市民們不安到什麼時候！"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"더러운 이능력자의 명단을 공개하라! 사회로부터 그들을 격리하고, 추방하라!","JPN":"忌々しい異能力者どものリストを公開しろ！　社会から彼らを隔離して追放しろ！","ENG":"Give us the list of all those dirty Supernaturals' names! Quarantine them from society and banish them!","TWN":"公開那些骯髒的超能力者的名單！將他們從社會中隔離並驅逐出去！"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"이렇게 늦은 밤까지…….","JPN":"こんな遅い時間まで……","ENG":"Don't they know what time it is...?","TWN":"都這麼晚了……"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"피곤하게들 사네. 다들 지치지도 않나 봐.","JPN":"本当に迷惑だわ。みんな元気ね。","ENG":"I mean, why are they doing this? Don't they know when to quit?","TWN":"大家都活得好累啊。都不覺得疲憊嗎？"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"왜 저렇게 서로가 서로를 못 잡아먹어서 안달일까?","JPN":"どうしてあんなに戦おうとするのかしら。","ENG":"Why are they so upset about not being able to tear each other apart?","TWN":"為什麼他們總是互相爭鬥，恨不得吃掉對方？"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"이능력자나 비능력자나 다들 똑같은 사람인데.","JPN":"異能力者も非能力者も、みんな同じ人間なのに。","ENG":"After all, Supernaturals are still people like us.","TWN":"超能力者也好，普通人也好，大家都是一樣的人。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"그들도 원해서 증표를 얻은 게 아니잖아. 비능력자들도 언제 증표를 얻게 될지 모르고.","JPN":"彼らだって好きで印を得たわけじゃないんでしょう？　非能力者だっていつ印を得ることになるかわからないんだし。","ENG":"It's not like they wanted to receive a mark. And normal people don't know whether they'll get one either.","TWN":"他們也不是自願的。普通人也不知道什麼時候會得到印記。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};